INSERT INTO public.reviews (id, product_id, user_id, rating, comment, created_at) VALUES
('f59b3900-99f8-4aa2-b316-2e4b9c2e03fa', 'ff1c7006-e2d4-45a2-89ca-82be640e6a84', '6135d4c3-544b-4895-adfc-beb3500e94f2', 5, 'Chất vải mịn, giặt máy vài lần rồi vẫn không thấy bị xù lông hay phai màu. Đồ đẹp lắm, 5 sao!', '2026-06-15T13:53:42.616825+00:00'),
('2feb1102-c486-4792-863f-08524a078270', 'ff1c7006-e2d4-45a2-89ca-82be640e6a84', '0755683d-1b4d-4f2d-a5fb-b60b707b79ed', 5, 'Áo thun chất vải cotton co giãn thoải mái, mặc rất mát tay, thấm hút tốt. Ủng hộ shop nhiệt tình nha.', '2026-07-02T06:23:42.616825+00:00'),
('d37f3ffe-e18f-472e-a1b5-80cacc6b474a', 'ff1c7006-e2d4-45a2-89ca-82be640e6a84', 'e287faec-8a60-4a59-a455-29809f2d7339', 5, 'Áo thun chất vải cotton co giãn thoải mái, mặc rất mát tay, thấm hút tốt.', '2026-07-07T13:59:42.616825+00:00'),
('44b0d21a-4bd6-4201-a3ff-cdd144410d5c', 'ff1c7006-e2d4-45a2-89ca-82be640e6a84', '0b5ef4bc-e0fb-4c99-8205-51bdf57b30cc', 5, 'Chất vải co giãn thoải mái, thấm hút mồ hôi tốt. Rất phù hợp mặc mùa hè. Khuyên mọi người nên mua thử.', '2026-06-14T08:34:42.616825+00:00'),
('2fce4ad2-fc09-48fd-8b67-e6d2555db33b', '33ed2ab4-1c78-4f84-ad9c-584332972637', '67a55df5-9806-414e-897a-66885bf4c9ea', 5, 'Chất vải mịn, giặt máy vài lần rồi vẫn không thấy bị xù lông hay phai màu. Rất đáng tiền mua nha mọi người.', '2026-07-06T08:11:42.616825+00:00'),
