('24ed9344-8346-4efc-89f0-ae03b7cad645', '7684ce70-4159-460b-8ca0-5a437fc25717', '46b49e4f-57f1-46a3-adaa-1e4a621a05be', 5, 'Phần cổ áo may cứng cáp, mặc lên đứng dáng và sang trọng.', '2026-04-28T18:25:42.616825+00:00'),
